-- ============================================================
-- Migration 057 — Oracle Predictions
-- ============================================================
-- AI-generated pre-match predictions for World Cup knockout fixtures,
-- shown as "The Oracle" mascot feature. Generated by a dedicated cron
-- (app/api/oracle/route.ts, lib/services/oracle.ts) via the Anthropic
-- API — separate from the API-Football score/fixture pipelines.

create table if not exists public.oracle_predictions (
  id                    uuid primary key default gen_random_uuid(),
  match_id              text not null unique references public.matches(id) on delete cascade,
  predicted_home_score  int not null,
  predicted_away_score  int not null,
  predicted_winner      text not null check (predicted_winner in ('home','away','draw')),
  confidence_pct        int not null check (confidence_pct between 0 and 100),
  reasoning_blurb       text not null,
  model                 text not null,
  generated_at          timestamptz not null default now()
);

alter table public.oracle_predictions enable row level security;

create policy "Anyone can read oracle predictions"
  on public.oracle_predictions for select
  using (true);

-- Written only by the Oracle generation cron (service role) — same
-- convention as points_snapshots (migration 054) and telegram_leaderboard_rank.
create policy "Service role manages oracle predictions"
  on public.oracle_predictions for insert
  with check (false);

create policy "Service role updates oracle predictions"
  on public.oracle_predictions for update
  using (false);
